return await (async function(eda) {
  const fixtureName = '__codex_example___DMT_Project_createProject_' + Date.now();
  const fixtureSlug = fixtureName.toLowerCase().replace(/[^a-z0-9]+/g, '-');
  const teams = await eda.dmt_Team.getAllTeamsInfo();
  const teamUuid = teams?.[0]?.uuid;
  if (!teamUuid) { throw new Error('当前账号下没有可用团队，无法解析 folderUuid。'); }
  const folderCandidates = await eda.dmt_Folder.getAllFoldersUuid(teamUuid);
  const folderUuid = folderCandidates?.[0];
  const created = await eda.dmt_Project.createProject(fixtureName, fixtureSlug, teamUuid, folderUuid, 'Generated by Codex example verification', undefined);
  const primitiveId = created?.getState_PrimitiveId?.() ?? created?.primitiveId ?? created?.id;
  if (primitiveId) {
    await eda.dmt_Project.delete([primitiveId]);
  }
  return {
    fixtureName,
    created,
    cleanupStrategy: 'auto',
  };
})(eda);
